New-Item -ItemType Directory -Force -Path "screens"

foreach ($screen in $screens) {
    $baseName = "screens\" + ($screen.name -replace '[^a-zA-Z0-9]', '_')
    $imgFile = $baseName + ".png"
    $htmlFile = $baseName + ".html"
    
    Write-Host "Downloading $($screen.name)..."
    curl.exe -sSL -o $imgFile $screen.imgUrl
    curl.exe -sSL -o $htmlFile $screen.htmlUrl
}
